#include <stdio.h>

/* == EXEMPLE ================================================
 * Bit fields: struct compacte avec tailles de bits explicites
 * =========================================================== */
typedef struct {
    unsigned int flag : 1;  /* 1 bit: 0 ou 1 */
    unsigned int mode : 3;  /* 3 bits: 0-7 */
    unsigned int id   : 4;  /* 4 bits: 0-15 */
} Control;

void example_bitfield(void) {
    Control c = {1, 5, 12};
    printf("flag=%u mode=%u id=%u size=%zu\n", c.flag, c.mode, c.id, sizeof(Control));
}

/* == VOTRE EXERCICE =========================================
 * Struct Instruction: opcode(7) rd(5) rs1(5) rs2(5) funct(10)
 * =========================================================== */

typedef struct {
    unsigned int opcode  : 7;
    unsigned int rd      : 5;
    unsigned int rs1     : 5;
    unsigned int rs2     : 5;
    unsigned int funct   : 10;
} Instruction;

int main(void) {
    Instruction inst;
    inst.opcode = 0x1F; inst.rd = 10; inst.rs1 = 5; inst.rs2 = 3; inst.funct = 0x2A;
    printf("opcode = 0x%02X\n", inst.opcode);
    printf("rd     = %u\n", inst.rd);
    printf("rs1    = %u\n", inst.rs1);
    printf("rs2    = %u\n", inst.rs2);
    printf("funct  = 0x%03X\n", inst.funct);
    printf("sizeof = %zu bytes\n", sizeof(Instruction));
    inst.opcode = 0xFF;
    printf("opcode overflow = 0x%02X\n", inst.opcode);
    return 0;
}

